    """A sequential container.

    Modules will be added to it in the order they are passed in the
    constructor. Alternatively, an `OrderedDict` of modules can be
    passed in. The `forward()` method of `Sequential` accepts any
    input and forwards it to the first module it contains. It then
    "chains" outputs to inputs sequentially for each subsequent module,
    finally returning the output of the last module.

    The value a `Sequential` provides over manually calling a sequence
    of modules is that it allows treating the whole container as a
    single module, such that performing a transformation on the
    `Sequential` applies to each of the modules it stores (which are
    each a registered submodule of the `Sequential`).

    What's the difference between a `Sequential` and a
    `msgflux.nn.ModuleList`? A `ModuleList` is exactly what it
    sounds like--a list for storing `Module`s! On the other hand,
    the layers in a `Sequential` are connected in a cascading way.

    !!! example
        ```python
        from collections import OrderedDict
        import msgflux.nn as nn
        class ExpertSales(nn.Module):
            def __init__(self):
                super().__init__()
                self.register_buffer("response", "Hi, let's talk?")

            def forward(self, msg: str):
                return msg + self.response

        class ExpertSupport(nn.Module):
            def __init__(self):
                super().__init__()
                self.register_buffer("response", "Hi, call 190")

            def forward(self, msg: str):
                return msg + self.response

        # Using Sequential to create a small workflow. When **expert** is run,
        # input will first be passed to **ExpertSales**. The output of
        # **ExpertSales** will be used as the input to the first
        # **ExpertSupport**; Finally, the output of
        # **ExpertSupport** will be the experts response.
        experts = nn.Sequential(ExpertSales(), ExpertSupport())
        experts("I need help with my tv.")

        # Using Sequential with OrderedDict. This is functionally the
        # same as the above code
        experts_dict = nn.Sequential(OrderedDict([
            ("expert_sales", ExpertSales()),
            ("expert_support", ExpertSupport())
        ]))
        experts_dict("I need help with my tv.")
        ```
    """

    _modules: Dict[str, Module] = OrderedDict()

    def __init__(self, *args: Union[Module, OrderedDict[str, Module]]):
        super().__init__()
        if len(args) == 1 and isinstance(args[0], OrderedDict):
            for key, module in args[0].items():
                self.add_module(key, module)
        else:
            for idx, module in enumerate(args):
                self.add_module(str(idx), module)

    def forward(self, *args, **kwargs) -&gt; Any:
        modules_iter = iter(self._modules.values())
        first_module = next(modules_iter)
        output = first_module(*args, **kwargs)

        for module in modules_iter:
            output = module(output)

        return output

    async def aforward(self, *args, **kwargs) -&gt; Any:
        """Async version of forward. Executes modules sequentially with async
        support.
        """
        modules_iter = iter(self._modules.values())
        first_module = next(modules_iter)

        # Check for acall method first, then coroutine function
        if hasattr(first_module, "acall"):
            output = await first_module.acall(*args, **kwargs)
        elif asyncio.iscoroutinefunction(first_module):
            output = await first_module(*args, **kwargs)
        else:
            # Fallback to sync call
            output = first_module(*args, **kwargs)

        for module in modules_iter:
            # Check for acall method first, then coroutine function
            if hasattr(module, "acall"):
                output = await module.acall(output)
            elif asyncio.iscoroutinefunction(module):
                output = await module(output)
            else:
                # Fallback to sync call
                output = module(output)

        return output

    def _get_mermaid(
        self,
        title: Optional[str] = None,
        orientation: Optional[str] = "TD",
    ) -&gt; str:
        mermaid_code = [
            "%%{",
            "        init: {",
            "            'theme': 'base',",
            "            'themeVariables': {",
            "            'primaryColor': '#E9E7E7',",
            "            'primaryTextColor': '#000000',",
            "            'primaryBorderColor': '#C0000',",
            "            'lineColor': '#F8B229',",
            "            'secondaryColor': '#91939C',",
            "            'tertiaryColor': '#fff'",
            "            }",
            "        }",
            "    }%%",
            f"flowchart {orientation}",
        ]

        if title:
            mermaid_code.insert(0, f"%% Title: {title}")

        mermaid_code.append("subgraph PARAMETERS")
        mermaid_code.append("direction LR")
        mermaid_code.append("param_msg([**msg**])")
        mermaid_code.append("end")

        first_node = None
        for i, module_name in enumerate(self._modules.keys()):
            node_id = f"node_{i}"
            if i == 0:
                first_node = node_id
            mermaid_code.append(f"{node_id}[ **msg = {module_name}﹙msg﹚** ]")

        for i in range(len(self._modules) - 1):
            mermaid_code.append(f"node_{i} --&gt; node_{i + 1}")

        last_node = f"node_{len(self._modules) - 1}"
        mermaid_code.append(f"{last_node} --&gt; node_return")
        mermaid_code.append("node_return([**return msg**])")

        if first_node:
            mermaid_code.append(f"PARAMETERS --&gt; {first_node}")

        mermaid_code.append("%% Styles")
        mermaid_code.append(
            "classDef terminal fill:#FFF4DD,stroke:#333,stroke-width:2px;"
        )
        mermaid_code.append(
            "classDef parameter fill:#FFF4DD,stroke:#333,stroke-width:px;"
        )

        for i in range(len(self._modules)):
            mermaid_code.append(f"class node_{i} default;")
        mermaid_code.append("class node_return terminal;")

        mermaid_code.append("class param_msg parameter;")

        return "\n".join(mermaid_code)

    def _get_item_by_idx(self, iterator, idx) -&gt; T:
        """Get the idx-th item of the iterator."""
        size = len(self)
        idx = operator.index(idx)
        if not -size &lt;= idx &lt; size:
            raise IndexError(f"index {idx} is out of range")
        idx %= size
        return next(islice(iterator, idx, None))

    def __getitem__(self, idx: Union[slice, int]) -&gt; Union["Sequential", T]:
        if isinstance(idx, slice):
            return self.__class__(OrderedDict(list(self._modules.items())[idx]))
        else:
            return self._get_item_by_idx(self._modules.values(), idx)

    def __setitem__(self, idx: int, module: Module) -&gt; None:
        key: str = self._get_item_by_idx(self._modules.keys(), idx)
        return setattr(self, key, module)

    def __delitem__(self, idx: Union[slice, int]) -&gt; None:
        if isinstance(idx, slice):
            for key in list(self._modules.keys())[idx]:
                delattr(self, key)
        else:
            key = self._get_item_by_idx(self._modules.keys(), idx)
            delattr(self, key)
        # To preserve numbering
        str_indices = [str(i) for i in range(len(self._modules))]
        self._modules = OrderedDict(list(zip(str_indices, self._modules.values())))

    def __len__(self) -&gt; int:
        return len(self._modules)

    def __add__(self, other) -&gt; "Sequential":
        if isinstance(other, Sequential):
            ret = Sequential()
            for layer in self:
                ret.append(layer)
            for layer in other:
                ret.append(layer)
            return ret
        else:
            raise ValueError(
                "add operator supports only objects "
                f"of Sequential class, but {type(other)!s} is given."
            )

    def pop(self, key: Union[int, slice]) -&gt; Module:
        v = self[key]
        del self[key]
        return v

    def __iadd__(self, other) -&gt; Self:
        if isinstance(other, Sequential):
            offset = len(self)
            for i, module in enumerate(other):
                self.add_module(str(i + offset), module)
            return self
        else:
            raise ValueError(
                "add operator supports only objects "
                f"of Sequential class, but {type(other)!s} is given."
            )

    def __dir__(self):
        keys = super().__dir__()
        keys = [key for key in keys if not key.isdigit()]
        return keys

    def __iter__(self) -&gt; Iterator[Module]:
        return iter(self._modules.values())

    def append(self, module: Module) -&gt; "Sequential":
        r"""Append a given module to the end.

        Args:
            module (nn.Module): module to append
        """
        self.add_module(str(len(self)), module)
        return self

    def insert(self, index: int, module: Module) -&gt; "Sequential":
        if not isinstance(module, Module):
            raise AssertionError(f"module should be of type: {Module}")
        n = len(self._modules)
        if not (-n &lt;= index &lt;= n):
            raise IndexError(f"Index out of range: {index}")
        if index &lt; 0:
            index += n
        for i in range(n, index, -1):
            self._modules[str(i)] = self._modules[str(i - 1)]
        self._modules[str(index)] = module
        return self

    def extend(self, sequential) -&gt; "Sequential":
        for layer in sequential:
            self.append(layer)
        return self
